def num_islands(grid):
    if not grid:
        return 0
    R, C = len(grid), len(grid[0])
    def sink(r, c):
        if 0 <= r < R and 0 <= c < C and grid[r][c] == 1:
            grid[r][c] = 0
            for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                sink(r+dr, c+dc)
    n = 0
    for r in range(R):
        for c in range(C):
            if grid[r][c] == 1:
                n += 1
                sink(r, c)
    return n
